{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the effective Rydberg energy from the 1s exciton binding energy and then applying the Rydberg formula for n=3, paying close attention to the sign convention for binding energy.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Calculate the effective Rydberg energy (Ry*) using the relationship between the band gap (Eg) and the 1s exciton peak energy (E_ex). Note that the binding energy (Eb) is defined as Eg - E_ex. For a hydrogenic model, the 1s binding energy is equal to Ry*. Determine the numerical value of Ry*."
    },
    {
      "label": "helper_2",
      "instructions": "Using the Ry* value obtained from the first step, calculate the energy level for the n=3 state using the formula E_n = -Ry* / (n^2). Ensure the sign convention reflects the bound state energy relative to the conduction band edge."
    }
  ],
  "synthesis_brief": "Combine the results by taking the Ry* value from helper 1 and the specific n=3 energy calculation from helper 2 to provide the final signed numerical value."
}

